/**
 * AiSuggestButton — a button that fetches an AI suggestion for a specific
 * task field and displays it as a tooltip / popover.
 */

import React, { useState, useCallback } from 'react';
import {
  IconButton,
  Tooltip,
  Popover,
  Box,
  Typography,
  Button,
  CircularProgress,
} from '@mui/material';
import AutoFixHighIcon from '@mui/icons-material/AutoFixHigh';

import { useProjectStore } from '../../stores';
import { useAiStore } from '../../stores/useAiStore';
import { aiApi } from '../../api';

interface AiSuggestButtonProps {
  taskName: string;
  field: 'duration' | 'dependency' | 'name' | 'resource' | 'general';
  context?: string;
  onAccept?: (suggestion: string) => void;
}

const AiSuggestButton: React.FC<AiSuggestButtonProps> = ({
  taskName,
  field,
  context,
  onAccept,
}) => {
  const activeProjectId = useProjectStore((s) => s.activeProjectId);
  const ollamaAvailable = useAiStore((s) => s.ollamaAvailable);
  const [anchorEl, setAnchorEl] = useState<HTMLElement | null>(null);
  const [loading, setLoading] = useState(false);
  const [suggestion, setSuggestion] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleClick = useCallback(
    async (e: React.MouseEvent<HTMLElement>) => {
      if (!activeProjectId) return;
      setAnchorEl(e.currentTarget);
      setLoading(true);
      setError(null);
      setSuggestion(null);

      try {
        const ctx = context
          ? { taskName, description: context }
          : { taskName };
        const result = await aiApi.suggest(activeProjectId, field, ctx);
        setSuggestion(result.suggestion);
      } catch (err: any) {
        setError(err.message ?? 'Failed to get suggestion');
      } finally {
        setLoading(false);
      }
    },
    [activeProjectId, taskName, field, context],
  );

  const handleClose = () => {
    setAnchorEl(null);
    setSuggestion(null);
    setError(null);
  };

  const handleAccept = () => {
    if (suggestion && onAccept) {
      onAccept(suggestion);
    }
    // Record feedback
    if (activeProjectId && suggestion) {
      aiApi.feedback(activeProjectId, field, { value: suggestion }, true).catch(() => {});
    }
    handleClose();
  };

  const handleDismiss = () => {
    if (activeProjectId && suggestion) {
      aiApi.feedback(activeProjectId, field, { value: suggestion }, false).catch(() => {});
    }
    handleClose();
  };

  if (!ollamaAvailable) return null;

  return (
    <>
      <Tooltip title={`AI Suggest ${field}`}>
        <IconButton size="small" onClick={handleClick} disabled={!activeProjectId}>
          <AutoFixHighIcon fontSize="small" sx={{ color: '#ff9800' }} />
        </IconButton>
      </Tooltip>
      <Popover
        open={Boolean(anchorEl)}
        anchorEl={anchorEl}
        onClose={handleClose}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'left' }}
      >
        <Box sx={{ p: 2, maxWidth: 320, minWidth: 200 }}>
          <Typography variant="subtitle2" gutterBottom>
            AI Suggestion
          </Typography>
          {loading && (
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <CircularProgress size={16} />
              <Typography variant="body2" color="text.secondary">
                Thinking...
              </Typography>
            </Box>
          )}
          {error && (
            <Typography variant="body2" color="error">
              {error}
            </Typography>
          )}
          {suggestion && (
            <>
              <Typography variant="body2" sx={{ mb: 1, whiteSpace: 'pre-wrap' }}>
                {suggestion}
              </Typography>
              <Box sx={{ display: 'flex', gap: 1, justifyContent: 'flex-end' }}>
                <Button size="small" onClick={handleDismiss}>
                  Dismiss
                </Button>
                {onAccept && (
                  <Button size="small" variant="contained" onClick={handleAccept}>
                    Accept
                  </Button>
                )}
              </Box>
            </>
          )}
        </Box>
      </Popover>
    </>
  );
};

export default AiSuggestButton;
